const claudeResponse = items[0].json;
const prevData = $node['Prepare Claude Prompt'].json;

// Extract JSON from Claude's response
let responseText = '';
if (claudeResponse.content && claudeResponse.content[0]) {
  responseText = claudeResponse.content[0].text || '';
}

// Try to parse JSON from the response (strip markdown code fences if present)
let parsed = {};
try {
  const jsonMatch = responseText.match(/```json\s*([\s\S]*?)```/) || responseText.match(/```\s*([\s\S]*?)```/);
  const jsonStr = jsonMatch ? jsonMatch[1].trim() : responseText.trim();
  parsed = JSON.parse(jsonStr);
} catch (e) {
  try {
    parsed = JSON.parse(responseText.trim());
  } catch (e2) {
    parsed = { error: 'Failed to parse rubric', raw: responseText };
  }
}

// Escape for SQL
const safeProgramme = (parsed.programme || '').replace(/'/g, "''");
const safeModuleName = (parsed.module_name || '').replace(/'/g, "''");
const safeAssessmentType = (parsed.assessment_type || '').replace(/'/g, "''");
const safeFilename = (prevData.filename || '').replace(/'/g, "''");
const safeParsedJson = JSON.stringify(parsed).replace(/'/g, "''");

return [{
  json: {
    token_id: prevData.token_id,
    token_code: prevData.token_code,
    programme: safeProgramme,
    module_name: safeModuleName,
    nqf_level: parsed.nqf_level || null,
    assessment_type: safeAssessmentType,
    total_marks: parsed.total_marks || 0,
    parsed_json: safeParsedJson,
    original_filename: safeFilename,
    parsed_raw: parsed
  }
}];
